// FIX: Read binary from the TRIGGER node, not the Code node
const triggerItems = $('Document Upload Trigger').all();
const item = triggerItems[0];

if (!item.binary || Object.keys(item.binary).length === 0) {
  return {
    text: 'No document was attached to this request. Please upload a file (PDF, image, or document).',
    hasBinary: false
  };
}

// Get first binary key (file field name)
const binaryKey = Object.keys(item.binary)[0];
const binaryData = item.binary[binaryKey];

return {
  text: `Document attached: ${binaryData.fileName || 'file'} (${binaryData.mimeType}). Please analyze and extract all relevant information.`,
  binary: item.binary,
  hasBinary: true,
  fileName: binaryData.fileName,
  mimeType: binaryData.mimeType
};

// Safely parse the AI's JSON output
const raw = $input.first().json.output || '';
let extractedData;
try {
  // Strip markdown fences if present
  const clean = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  extractedData = JSON.parse(clean);
} catch (e) {
  // If not valid JSON, return the raw text in a wrapper
  extractedData = { raw_output: raw, parse_error: e.message };
}

return [{ json: { extractedData, success: !extractedData.parse_error } }];
